import React,{useEffect,useMemo,useState}from"react";import{MessageSquare,Send}from"lucide-react";import{vendorAPI,formatDate,safeArray}from"../../services/api.js";import{useToast}from"../../components/ui/Toast.jsx";import{PageHeader}from"../../components/ui/PortalUI.jsx";
export default function VendorMessagesPage(){const{showToast}=useToast();const[items,setItems]=useState([]);const[keyword,setKeyword]=useState("");const[active,setActive]=useState(null);const[msg,setMsg]=useState("");const load=async()=>{try{const list=safeArray(await vendorAPI.conversations());setItems(list);setActive(a=>a||list[0]||null)}catch(e){showToast(e.message,"error")}};useEffect(()=>{load()},[]);const rows=useMemo(()=>items.filter(x=>[x.customer?.full_name,x.last_message,x.move?.job_id].filter(Boolean).join(" ").toLowerCase().includes(keyword.toLowerCase())),[items,keyword]);const send=async()=>{if(!msg.trim()||!active)return;try{await vendorAPI.sendMessage(active.id,{message:msg});showToast("Message sent");setMsg("");load()}catch(e){showToast(e.message,"error")}};return <div className="page-wrap"><PageHeader icon={MessageSquare} title="Messages" subtitle="Communicate with customers and AnQ Movers." search={keyword} onSearch={setKeyword} placeholder="Search messages..."/><section className="chat-layout"><div className="chat-list">{rows.map(c=><button key={c.id} className={`chat-item ${active?.id===c.id?"active":""}`} onClick={()=>setActive(c)}><div className="vendor-badge" style={{width:34,height:34,fontSize:12}}>{(c.customer?.full_name||"C").slice(0,1)}</div><div><b>{c.customer?.full_name||c.move?.job_id||"Customer"}</b><p>{c.last_message||"No message yet"}</p><small>{formatDate(c.updated_at)}</small></div></button>)}</div><div className="chat-window"><div className="chat-head"><b>{active?.customer?.full_name||"Customer"}</b><p className="muted-copy">{active?.move?.job_id||"Conversation"}</p></div><div className="chat-body"><div className="bubble">Can you confirm availability and price?</div><div className="bubble me">Yes, we are available and pricing is confirmed.</div><div className="bubble">Thanks, please upload the updated quote.</div></div><div className="chat-compose"><input value={msg} onChange={e=>setMsg(e.target.value)} placeholder="Type your message..."/><button className="red-btn" onClick={send}><Send size={15}/></button></div></div></section></div>}
